import{_ as a,r as d,o as l,c as s,b as e,e as o,w as c,d as r,f as n}from"./app-55c326ac.js";const u={},h=e("h1",{id:"_01-什么是docker",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_01-什么是docker","aria-hidden":"true"},"#"),r(" 01. 什么是Docker")],-1),k={class:"table-of-contents"},g=n('<p>Docker：有dotCloub公司创始人 Solomon Hykes 在法国期间发起的一个公司内部项目。主要项目代码在 GitHub 上进行维护。 Docker使用Google欧公司退出的GO语言进行开发实现。基于Linux内核的cgroup，namespace，以及AUFS类的Union FS等技术，<strong>对进程进行封装隔离，属于操作系统层面的虚拟化技术</strong> 由于隔离的进程独立于宿主和其他的隔离的进程，因此为成为<strong>容器</strong><br> Docker在容器的基础上，进行了进一步的封装，从文件系统、网络互联到进程隔离等等，几大的简化了容器的创建和维护，使Docker技术比虚拟机技术更为轻便、快捷。 <strong>Docker 与 Virtual Machines比较：</strong><br> Virtual Machines（传统虚拟机）：是虚拟出一套硬件后，在其上运行一个完成操作系统，在该系统上在运行所需应用进程<br> 容器：的应用进程直接运行与宿主的内核，容器内没有自己的内核，而且也没有进行硬件虚拟。<br><strong>So：</strong> 容器比传统虚拟机更为轻便</p><h2 id="为什么要用docker" tabindex="-1"><a class="header-anchor" href="#为什么要用docker" aria-hidden="true">#</a> 为什么要用docker</h2><ul><li><strong>1.更高效的利用系统资源</strong><br> 由于容器不需要进行硬件虚拟以及运行完整操作系统等额外开销，Docker对系统资源的利用率更高。无论是应用执行速度，内存损耗或者文件存储速度，都要比传统虚拟机技术更高效。所以，相比虚拟机技术，一个相同配置的主机，往往可以运行更多数量的应用</li><li><strong>2.更快速的启动时间</strong><br> 传统的虚拟机技术启动应用服务往往需要数分钟，而Docker容器应用，由于直接运行于宿主内核，无需启动完整的操作系统，因此可以做好秒级、甚至毫秒级的启动。节约了开发、测试、部署的时间</li><li><strong>3.一致的运行环境</strong><br> 开发过程中一个常见的问题是环境一致性问题。由于开发环境、测试环境、生产环境不一致，导致有些 bug 并未在开发过程中被发现。而 Docker 的镜像提供了除内核外完整的运行时环境，确保了应用运行环境一致性，从而不会再出现 「这段代码在我机器上没问题啊」 这类问题。</li><li><strong>4.持续交付和部署</strong><br> 对开发和运维（DevOps）人员来说，最希望的就是一次创建或配置，可以在任意地方正常运行。<br> 使用Docker可以通过定制应用镜像来实现持续集成、持续交付、部署。开发人员可以通过Dockerfile来进行镜像构建，并结合持续集成系统进行集成测试，而运维人员则可以直接在生产环境中快速部署该镜像，甚至结合持续部署系统进行自动部署。<br> 使用<code>Dockerfile</code>使镜像构建透明化，不仅仅开发团队可以理解应用运行环境，也方便运维团队理解应用运行所需条件。</li><li><strong>5.更轻松地迁移</strong><br> 由于Docker确保了执行环境的一致性，使得应用的迁移更加容易。Docker可以再很多平台上运行，无论是虚拟机，物理机，公有云，私有云，甚至是笔记本，其运行结果是一直的。因此用户可以很轻易的将在一个平台上运行的应用，迁移到另一个平台上，而不用担心运行环境的幻化导致应用无法正常运行的情况。</li><li><strong>6.更轻松地维护和拓展</strong><br> Docker使用的分层存储以及镜像的技术，使得应用重复部分的复用更为容易，也使应用的维护更新更加简单，基于基础镜像进一步扩展镜像也变得简单。此外，Docker 团队同各个开源项目团队一起维护了一大批高质量的 官方镜像，既可以直接在生产环境使用，又可以作为基础进一步定制，大大的降低了应用服务的镜像制作成本。</li></ul><h4 id="对比传统虚拟机" tabindex="-1"><a class="header-anchor" href="#对比传统虚拟机" aria-hidden="true">#</a> 对比传统虚拟机</h4><table><thead><tr><th>特性</th><th>容器</th><th>虚拟机</th></tr></thead><tbody><tr><td>启动</td><td>秒级</td><td>分钟级</td></tr><tr><td>硬盘使用</td><td>一般为MB</td><td>一般为GB</td></tr><tr><td>性能</td><td>接近原生</td><td>弱于原生</td></tr><tr><td>系统支持量</td><td>单机支持上千个容器</td><td>一般几十个</td></tr></tbody></table><hr><h2 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念" aria-hidden="true">#</a> 基本概念</h2><p>Docker包括三个基本概念</p><ul><li>镜像（Image）</li><li>容器（Container）</li><li>仓库（Repository）</li><li>理解了这三个概念，就理解了 Docker 的整个生命周期。</li></ul><h2 id="docker-镜像" tabindex="-1"><a class="header-anchor" href="#docker-镜像" aria-hidden="true">#</a> Docker 镜像</h2><p>操作系统分为内核和用户空间。对于Linux而言，内核启动后，会挂载<code>root</code>文件系统为其提供用户空间支持。而Docker镜像（Image），就相当于是一个<code>root</code>文件系统。比如官方镜像<code>ubuntu18.04</code>就包含了完整的一套Ubuntu18.04最小系统的<code>root</code>文件系统</p><h3 id="分层存储" tabindex="-1"><a class="header-anchor" href="#分层存储" aria-hidden="true">#</a> 分层存储</h3><p>因为镜像包含操作系统完整的<code>root</code>文件系统，其体积往往是庞大的。因此在Docker设计时，就充分利用Union FS的技术，将其设计为分层存储的架构。所以，严格来说，镜像并非是像一个ISO那样的打包文件，镜像只是一个虚拟的概念，其实际体现并非由一个文件组成，而是由一组文件系统组成，或者说，由多层文件系统联合组成。<br> 镜像构建时，会一层层构建，前一层是后一层的基础。每一层构建完就不会再发生改变，后一层上的任何改变只发生在自己这一层。比如，删除前一层文件的操作，实际不是真的删除前一层的文件，而是仅在当前层标记为该文件已删除。在最终容器运行的时候，虽然不会看到这个文件，但是实际上改文件会一直跟随镜像。<strong>so：在构建镜像的时候，需要细心，每一层尽量只包含该层需要添加的东西，任何额外的东西应该在该层构建结束前清理掉。</strong><br> 分层存储的特征还使得镜像等额复用、定制变的更为容易。甚至可以用之前构建好的镜像作为基础层，然后进一步添加新的层，以定制自己所需的内容，构建新的镜像</p>',13),D=e("br",null,null,-1),b=e("br",null,null,-1),_=e("br",null,null,-1),p={href:"https://coolshell.cn/articles/17061.html",target:"_blank",rel:"noopener noreferrer"},y=n('<hr><h2 id="docker-容器-container" tabindex="-1"><a class="header-anchor" href="#docker-容器-container" aria-hidden="true">#</a> Docker 容器（Container）</h2><p>镜像（Image）与容器（Container）的关系，就像是面向对象程序设计中的<code>类</code>和<code>示例</code>一样,镜像是静态的定义，容器是镜像运行时的实体。容器可以被创建，启动，停止，删除，暂停等等。<br> 容器的实质是进程，但与直接在宿主执行的进程不同，容器进程运行于属于自己的独立的<code>命名空间</code>。因此容器可以拥有自己的<code>root</code>文件系统、自己的网络配置，自己的进程空间，甚至自己的用户ID空间。容器内的进程是运行在一个隔离的环境里，使用起来，就好像是在一个独立于宿主的系统下操作一样。这种特性使得容器封装的应用比直接在宿主运行更加安全。也因为这种隔离的特性，很多人初学Docker时会混淆容器和虚拟机。<br> 镜像使用的是分层存储，容器也是。每一个容器运行时，是以镜像为基础层，在其上创建一个当前容器的存储层，可以称这个为容器运行时读写而准备的存储层为容器存储层。<br> 容器存储层的生命周期和容器一样，容器消亡时，容器存储层也随之消亡。因此，任何保存于容器存储层的信息都会随容器删除而丢失。<br> 按Docker最佳实践的要求，容器不应该向其存储层内写入任何数据，容器岑储层要保持无状态化。所有的文件写入操作，都应该使用<code>数据卷</code>，或者绑定宿主目录，在这些位置的读写会跳过容器存储层，直接对宿主（或网路存储）发生读写，其性能和稳定性更高。<br> 是数据卷的生命周期独立于容器，容器消亡，数据卷不会消亡。因此，使用数据卷后，容器删除或者重新运行之后，数据不会丢失</p><h2 id="docker-registry" tabindex="-1"><a class="header-anchor" href="#docker-registry" aria-hidden="true">#</a> Docker Registry</h2><p>镜像构建完成后，可以容易的在当前宿主机上运行，但是，如果需要在其他服务器上使用这个镜像，我们就需要一个集中的存储，分发镜像的服务，Docker Registry就是这样的服务<br> 一个 <code>Docker Registry</code>中可以包含多个<code>仓库</code>（Repository）；每个仓库可以包含多个<code>标签</code>（Tag）；每个标签对应一个镜像<br> 通常，一个仓库会包含同一个软件不同版本的镜像，而标签就常用于对应该软件的各个版本。我们可以通过 <code>&lt;仓库名&gt;:&lt;标签&gt;</code> 的格式来指定具体是这个软件哪个版本的镜像。如果不给出标签，将以 <code>latest</code> 作为默认标签。<br> 以 Ubuntu 镜像 为例，ubuntu 是仓库的名字，其内包含有不同的版本标签，如，<code>16.04, 18.04</code>。我们可以通过 <code>ubuntu:14.04</code>，或者 <code>ubuntu:18.04</code> 来具体指定所需哪个版本的镜像。如果忽略了标签，比如 ubuntu，那将视为 <code>ubuntu:latest</code>。</p><p>仓库名经常以 两段式路径 形式出现，比如 <code>jwilder/nginx-proxy</code>，前者往往意味着 Docker Registry 多用户环境下的用户名，后者则往往是对应的软件名。但这并非绝对，取决于所使用的具体 Docker Registry 的软件或服务</p><h3 id="docker-registry公开服务" tabindex="-1"><a class="header-anchor" href="#docker-registry公开服务" aria-hidden="true">#</a> Docker Registry公开服务</h3><p>Docker Registry 公开服务是开放给用户使用、允许用户管理镜像的 Registry 服务。一般这类公开服务允许用户免费上传、下载公开的镜像，并可能提供收费服务供用户管理私有镜像。</p><p>最常使用的 Registry 公开服务是官方的 Docker Hub，这也是默认的 Registry，并拥有大量的高质量的官方镜像。除此以外，还有 CoreOS 的 Quay.io，CoreOS 相关的镜像存储在这里；Google 的 Google Container Registry，Kubernetes 的镜像使用的就是这个服务。</p><p>由于某些原因，在国内访问这些服务可能会比较慢。国内的一些云服务商提供了针对 Docker Hub 的镜像服务（Registry Mirror），这些镜像服务被称为加速器。常见的有 阿里云加速器、DaoCloud 加速器 等。使用加速器会直接从国内的地址下载 Docker Hub 的镜像，比直接从 Docker Hub 下载速度会提高很多。在 安装 Docker 一节中有详细的配置方法。</p><p>国内也有一些云服务商提供类似于 Docker Hub 的公开服务。比如 时速云镜像仓库、网易云镜像服务、DaoCloud 镜像市场、阿里云镜像库 等。</p><h3 id="私有-docker-registry" tabindex="-1"><a class="header-anchor" href="#私有-docker-registry" aria-hidden="true">#</a> 私有 Docker Registry</h3><p>除了使用公开服务外，用户还可以在本地搭建私有 Docker Registry。Docker 官方提供了 Docker Registry 镜像，可以直接使用做为私有 Registry 服务。在 私有仓库 一节中，会有进一步的搭建私有 Registry 服务的讲解。</p><p>开源的 Docker Registry 镜像只提供了 Docker Registry API 的服务端实现，足以支持 docker 命令，不影响使用。但不包含图形界面，以及镜像维护、用户管理、访问控制等高级功能。在官方的商业化版本 Docker Trusted Registry 中，提供了这些高级功能。</p><p>除了官方的 Docker Registry 外，还有第三方软件实现了 Docker Registry API，甚至提供了用户界面以及一些高级功能。比如，VMWare Harbor 和 Sonatype Nexus。</p>',15);function f(R,x){const t=d("router-link"),i=d("ExternalLinkIcon");return l(),s("div",null,[h,e("nav",k,[e("ul",null,[e("li",null,[o(t,{to:"#为什么要用docker"},{default:c(()=>[r("为什么要用docker")]),_:1})]),e("li",null,[o(t,{to:"#基本概念"},{default:c(()=>[r("基本概念")]),_:1})]),e("li",null,[o(t,{to:"#docker-镜像"},{default:c(()=>[r("Docker 镜像")]),_:1}),e("ul",null,[e("li",null,[o(t,{to:"#分层存储"},{default:c(()=>[r("分层存储")]),_:1})])])]),e("li",null,[o(t,{to:"#docker-容器-container"},{default:c(()=>[r("Docker 容器（Container）")]),_:1})]),e("li",null,[o(t,{to:"#docker-registry"},{default:c(()=>[r("Docker Registry")]),_:1}),e("ul",null,[e("li",null,[o(t,{to:"#docker-registry公开服务"},{default:c(()=>[r("Docker Registry公开服务")]),_:1})]),e("li",null,[o(t,{to:"#私有-docker-registry"},{default:c(()=>[r("私有 Docker Registry")]),_:1})])])])])]),g,e("blockquote",null,[e("p",null,[r("Union FS技术："),D,r(" 所谓UnionFs就是把不同物理位置的目录合并mount到同一个目录中。"),b,r(" UnionFS的一个最主要的应用是：把一张CD/DVD和一个硬盘目录联合mount在一起，然后，就可以对这个只读的CD/DVD上的文件进行修改"),_,r(" 参考："),e("a",p,[r("Union FS"),o(i)])])]),y])}const C=a(u,[["render",f],["__file","Docker系列学习-01.docker介绍.html.vue"]]);export{C as default};
